[ITALIC: The new parameter fields are:
] [CODE: default[ITALIC:factory]
[ITALIC: [CODE: alias]priority]
] [CODE: validation[ITALIC:alias]
[ITALIC: [CODE: serialization]alias]
] [CODE: discriminator]
[ITALIC: [CODE: strict]
] [CODE: multiple[ITALIC:of]
[ITALIC: [CODE: allow]inf[ITALIC:nan]
] [CODE: max]digits]
[ITALIC: [CODE: decimal[ITALIC:places]
] [CODE: json]schema[ITALIC:extra]
